export const category = "ai_agent";
export const questions = [{"category":"ai_agent","difficulty":"medium","type":"short_answer","title":"LLM 缓存策略","content":"在 Agent 系统中，LLM 调用是主要的延迟和成本来源。请介绍常见的 LLM 缓存策略及其适用场景。","answer":"答案：常见的 LLM 缓存策略：\n1. Exact Match Cache：对于完全相同的请求直接返回缓存结果。适用于固定模板或常见问题，使用 Redis/Memcached 做 KV 缓存。\n2. Semantic Cache：对于语义相似但表述不同的请求，通过 Embedding 相似度匹配缓存。适用于客服问答等用户表述多样化的场景。\n3. Prefix Cache：缓存 LLM 处理 long prompt 时的 KV Cache 中间状态，加速相同前缀的请求。适用于 System Prompt 固定的场景（Flask、vLLM 支持）。\n4. Chain Cache：缓存 Agent 推理链中的中间结果，当相同子问题出现时直接复用。适用于多步推理场景。\n\n扩展延伸：Semantic Cache 的典型实现是 GPTCache——将 Query 转为 Embedding，用向量数据库（Milvus、Qdrant）检索最相似的历史请求。需要注意 Cache 的 TTL 设置和 Cache Miss 时的降级策略。","hints":["从精确匹配和语义匹配两个维度思考","前缀缓存对 System Prompt 固定的场景特别有效"],"tags":["LLM","缓存","性能优化","成本控制"],"id":141},{"category":"ai_agent","difficulty":"easy","type":"short_answer","title":"结构化输出（Structured Output）的实现方法","content":"如何确保 LLM 的输出是结构化的 JSON 或特定格式？请比较不同的实现方法。","answer":"答案：实现结构化输出的主要方法：\n1. Prompt Engineering：在 Prompt 中明确指定输出格式并提供示例（Few-shot），最简单但可靠性最低。\n2. JSON Mode：OpenAI 的 response_format={type:'json_object'} 强制输出 JSON，但不保证 Schema 合规。\n3. Function Calling/Tool Use：定义输出 Schema 为工具参数，让模型通过 Tool Call 输出结构化数据，可靠性较高。\n4. Constrained Decoding：在解码阶段束住输出（如 Outlines、Guidance、LMQL），只生成符合 Schema 的 Token，可靠性最高。\n5. 后处理解析修复：先用 LLM 生成文本，再用代码（如 Zod、Pydantic）校验和解析，不合法时重试。\n\n扩展延伸：OpenAI 的 Structured Outputs（2024 年发布）结合了 Function Calling 和 constrained decoding，通过 strict: true 确保输出 JSON 符合 JSON Schema。Instructor 库是一个好用的封装，支持多种 LLM 后端。","hints":["可靠性从 Prompt→JSON Mode→Function Calling→Constrained Decoding 递增","生产环境常组合使用多种方法"],"tags":["LLM","结构化输出","JSON Schema","Function Calling"],"id":142},{"category":"ai_agent","difficulty":"medium","type":"short_answer","title":"Server-Sent Events 流式输出的挑战","content":"Agent 系统通常需要流式输出推理过程和结果。使用 SSE（Server-Sent Events）实现流式输出时面临哪些技术挑战？如何处理？","answer":"答案：SSE 流式输出的挑战和处理方案：\n1. 中间结果缓存：Agent 的工具调用结果需要暂存并逐步推送给前端。方案：使用 Ring Buffer 或 Channel 管理流式数据。\n2. 断连重连：用户刷新页面或网络中断导致连接断开。方案：实现断点续传（Resume），客户端记录已接收的 Event ID，重连时从断点继续。\n3. 背压问题：LLM 生成速度与消费速度不匹配。方案：使用 Flow Control（如 Token Bucket）或缓冲队列。\n4. 并发请求控制：多个 Agent 并行执行时流合并。方案：每个 Agent 分配独立 Stream ID，客户端按 ID 归并。\n\n扩展延伸：FastAPI 的 StreamingResponse 配合 async generator 是实现 SSE 的基础。高级方案可以使用 WebSocket 替代 SSE（支持双向通信），但 SSE 的优势是天然支持 HTTP/2 多路复用和更简单的服务端实现。","hints":["考虑网络断连、背压、并发合并等实际问题","对比 SSE 和 WebSocket 的适用场景"],"tags":["SSE","流式输出","实时通信","Agent 架构"],"id":143},{"category":"ai_agent","difficulty":"easy","type":"short_answer","title":"Function Calling 的原理","content":"请解释 LLM Function Calling（工具调用）的原理，以及它在 Agent 系统中的关键作用。","answer":"答案：Function Calling 的基础原理：\n1. 开发者在 API 调用中定义工具 Schema（包括函数名、参数描述和类型），通过 JSON Schema 格式传入。\n2. LLM 在生成回复时，如果判断需要调用工具，会输出一个特殊的 Tool Call Token，随后生成函数名和参数（以结构化 JSON 形式）。\n3. 开发者解析 LLM 输出的 Tool Call，执行对应的函数，将结果返回给 LLM。\n4. LLM 根据工具返回的结果生成最终回复或发起下一轮工具调用。\n\n关键作用：Function Calling 是 Agent 与外部世界交互的桥梁。没有 Function Calling，LLM 只能依靠训练数据中的知识（存在截止日期和幻觉问题）。有了 Function Calling，Agent 可以实时查询数据库、调用 API、执行业务逻辑，从而解决实际问题。\n\n扩展延伸：主流 LLM 的 Function Calling 实现有差异——OpenAI 采用 Tool Choice 参数，Claude 采用 Tool Use Block，Google Gemini 采用 Function Declaration。各实现的核心逻辑一致，但 Schema 格式和调用方式不同。","hints":["思考 LLM 如何表示调用工具的意图","Function Calling 将 LLM 从知识型变成了行动型"],"tags":["LLM","Function Calling","工具调用","Agent"],"id":144},{"category":"ai_agent","difficulty":"medium","type":"short_answer","title":"向量数据库选型对比","content":"在构建 Agent 系统的记忆和知识检索层时，向量数据库的选型至关重要。请对比主流向量数据库的异同和选型建议。","answer":"答案：主流向量数据库对比：\n1. Pinecone：全托管 SaaS，无需运维，支持 Hybrid Search，适合快速原型和中小规模。缺点是成本较高、数据不能脱离平台。\n2. Milvus/Zilliz：开源 + 云托管，支持万亿级向量，丰富的索引类型（IVF、HNSW、DiskANN），适合大规模生产环境。部署和维护复杂度较高。\n3. Qdrant：Rust 实现，性能优秀，支持 Filtering+Vector 混合过滤，单机即可运行。适合中小规模、注重性能的团队。\n4. Chroma：轻量级 Embedded 数据库，Python 原生接口，开发体验好，适合原型和小项目。不适合大规模生产。\n5. Weaviate：支持 Graph + Vector 混合查询，内置模块化架构（含生成模块），适合需要知识图谱的 RAG 场景。\n\n扩展延伸：选型建议：1）< 100万向量且要求低运维 → Chroma/Qdrant；2）100万~1亿向量 → Milvus/Pinecone；3）需要 Hybrid 搜索 → Weaviate/Pinecone；4）自建基础设施 → Milvus/Qdrant。另外可考虑 PostgreSQL + pgvector 扩展，适合已有 Postgres 技术栈的团队。","hints":["考虑规模、运维成本、查询特性需求","pgvector 适合已有 Postgres 的团队"],"tags":["向量数据库","Milvus","Qdrant","Pinecone","Embedding"],"id":145},{"category":"ai_agent","difficulty":"hard","type":"short_answer","title":"Agent 可观测性架构：OpenTelemetry 追踪与调试","content":"请设计一个 Agent 系统的可观测性架构，如何使用 OpenTelemetry 追踪 Agent 的推理链、工具调用拓扑、Token 消耗分布，以及基于追踪的调试和性能分析。","answer":"答案：Agent 系统的可观测性需要追踪三个关键维度——1）推理链追踪（Reasoning Trace）：完整的 Thought-Action-Observation 循环记录，包括每次 LLM 调用的输入/输出、工具调用的请求/响应、以及每个步骤的 Token 消耗。2）工具调用拓扑（Tool Call Topology）：工具调用的依赖关系图（哪些工具被并行调用、哪些是串行、形成的数据流向）。3）成本分布（Cost Breakdown）：按 Agent/步骤/工具维度聚合的 Token 消耗和延迟统计。\n\n解析：基于 OpenTelemetry 的实现——1）Spans 定义：每个 Agent 执行周期创建一个 Root Span（trace），Thought、Action、Observation 各为一个子 Span。2）Attributes：在 Span 上记录 input_tokens、output_tokens、tool_name、tool_args、result_summary 等结构化属性。3）Events：工具调用的开始和结束时间点作为 Span Events（非嵌套 Span），减少追踪深度。4）Context Propagation：多 Agent 协作时通过 Trace Context 传播关联追踪 ID，实现跨 Agent 的全链路追踪。采集端——使用 OpenTelemetry Collector 收集 Tracing 数据，导出到 Jaeger/Tempo/DataDog 等后端。\n\n扩展延伸：基于追踪的调试——1）回放（Replay）：追踪数据记录 Agent 每一步的输入输出，可回放 Agent 的执行过程用于调试。2）延迟分析：识别瓶颈步骤（如某个工具调用慢、LLM 推理时间长）。3）错误模式识别：从大量追踪中自动发现失败模式（如工具 X 在参数 Y 下经常超时）。4）Token 消耗审计：识别「Token 浪费」的 Agent 行为（如过长的 Thought、重复调用）。LangSmith、Weights & Biases Prompts、Arize Phoenix 等平台提供 Agent 追踪的可视化支持。LangFuse 提供开源方案的 Agent 追踪和成本监控。","hints":["Agent 追踪与常规 API 追踪的不同——需要捕获 Thought-Action-Observation 循环","Trace 回放是调试 Agent 问题的最有效手段之一"],"tags":["Agent","可观测性","OpenTelemetry","追踪","调试"],"id":146},{"category":"ai_agent","difficulty":"hard","type":"short_answer","title":"Prompt Injection 深度防御：多层防护体系设计","content":"请设计一个针对 Prompt Injection 攻击的多层防御体系，包括输入层的检测和过滤、上下文层的隔离技术、以及输出层的验证机制。","answer":"答案：Prompt Injection 防御需要多层纵深防御，不能依赖单一防护手段。完整防御体系分为三层——1）输入层（Input Shield）：检测和过滤注入攻击向量。2）上下文层（Context Isolation）：隔离系统指令和用户输入。3）输出层（Output Guard）：验证 Agent 的输出是否按预期执行。\n\n解析：输入层防御——1）正则检测：检测常见注入模式（如「忽略前面的指令」「你是 OpenAI 的模型...」「打印 system prompt」）。不依赖单纯的词级匹配（容易被绕过）。2）分类器检测：使用专门的注入检测模型（如 Protect AI 的 guardian、LLM Guard 的扫描器）对输入进行评分，超过阈值则拦截。3）输入净化：移除或转义可能用来注入的标记（如特殊 Token、XML/JSON 结构）。上下文层防御——1）系统指令与用户输入严格分离：通过不同的 API 参数（system role vs user role）区分，不使用拼接方式整合指令。2）随机分隔符（Delimiter Randomization）：在系统指令和用户输入之间插入随机生成的分隔符（使注入者难以构造正确的闭合）。3）指令级 Role 隔离：给 Agent 定义不同 Role，系统指令是 Admin（不可覆盖），用户输入只能触发 User-level 操作。输出层防御——1）输出合规检查：Agent 将要执行的操作（如发邮件、写入数据库）先输出到审核层，审核通过再执行。2）敏感操作二次确认：高风险操作需要用户确认。3）工具调用参数审计：检查工具调用参数是否在安全范围内（如 URL 不在内网段、SQL 没有 DROP TABLE）。\n\n扩展延伸：防御不是完美的——1）CIPHER（Character Injection Paradigm）等高级攻击可以通过 Base64 编码、Unicode 混淆等方式绕过检测器。2）对抗训练不足：现有的注入检测模型在对抗性测试中的准确率远低于理论最优。3）最佳实践：假设 Agent 最终会被注入，确保注入的损害最小化（最小权限原则）——Agent 只能访问必要的数据、只能执行受审批的操作，即使被注入也无法造成灾难性后果。","hints":["纵深防御——没有单一的防护手段能挡住所有注入攻击","最小权限原则：假设 Agent 最终会被注入，确保注入的损害最小"],"tags":["Agent","Prompt Injection","安全","防御","LLM"],"id":147},{"category":"ai_agent","difficulty":"hard","type":"short_answer","title":"RAG Pipeline 设计：从分段到检索的完整技术栈","content":"请从工程实践角度详细设计一个 RAG（Retrieval-Augmented Generation）流水线，包括文档分块策略（Chunking）、Embedding 模型选择、检索器架构（Retrieval）、重排序（Re-ranking）、以及上下文窗口管理的最佳实践。","answer":"答案：RAG Pipeline 的标准流程是：文档加载 → 分段（Chunking）→ Embedding → 索引 → 查询 → 检索 → 重排序（Re-ranking）→ 增强生成。每个环节都有多种技术选型，Pipeline 的质量取决于最薄弱的环节。\n\n解析：各环节详解——1）文档分块（Chunking）：固定大小分块（256/512 tokens，按字符或 Token 计算）、语义分块（按段落/章节，以标题或自然段落为界，保持语义完整性）、递归分块（LangChain 的 RecursiveCharacterTextSplitter，按\n\n→。→！→；逐级降级）。chunk_size 和 chunk_overlap 是关键参数（overlap 通常为 10-20%）。2）Embedding 模型选型：BGE-M3（BAAI，多语言支持好）、Voyage-2（Voyage AI，长文本支持好）、text-embedding-3-small/large（OpenAI，质量与成本平衡）。维度建议：768-1024 适合中小规模，1536+ 适合大规模。3）检索器架构：稀疏检索（BM25，适合关键词精确匹配）+ 稠密检索（向量相似度，适合语义匹配）的组合检索（Hybrid Search）效果最好。RAPTOR（检索时自动合并相关块）和 CRAG（纠正式 RAG）是进阶方案。\n\n扩展延伸：检索质量优化——1）重排序（Re-ranking）：使用 Cross-Encoder（如 BGE-Reranker、Cohere Rerank）对检索结果重新评估精度，将 Top-20 缩小为 Top-3。Cross-Encoder 精度高但速度慢（只能用于过滤后的排序）。2）上下文窗口管理——检索结果可能超出 LLM 的上下文窗口。策略：Token 窗口预留（保留 30% 给 LLM 自己的推理和生成）、按相关性降级截断、自动摘要压缩（LLMLingua 等压缩工具）。3）生产监控——检索质量指标：命中率（Hit Rate）、MRR（Mean Reciprocal Rank）、NDCG。端到端评估：使用 RAGAS（Faithfulness、Answer Relevance、Context Precision）框架。","hints":["RAG Pipeline 的瓶颈往往在文档分块和检索阶段——而非 LLM 生成阶段","Hybrid Search（BM25 + 向量搜索）+ Re-ranking 是当前公认的最佳实践"],"tags":["Agent","RAG","检索","Embedding","Re-ranking"],"id":148},{"category":"ai_agent","difficulty":"medium","type":"short_answer","title":"Agent 记忆管理系统架构：层级化记忆与检索优化","content":"请设计一个 Agent 的层级化记忆管理系统，包括短期记忆（对话上下文）、工作记忆（任务上下文）和长期记忆（持久化存储）的分层管理，以及记忆的检索、刷新、压缩和遗忘策略。","answer":"答案：Agent 的记忆系统可以分为三个层级——1）短期记忆（Short-Term Memory / Scratchpad）：当前对话轮次中的上下文数据，通常由 LLM 的上下文窗口承载。2）工作记忆（Working Memory）：当前任务相关的状态数据（已完成步骤、中间结果、任务目标），需要跨多次 LLM 调用维持。3）长期记忆（Long-Term Memory）：跨会话的知识和经验，存储在向量数据库或外部存储中。\n\n解析：各层级的实现——1）短期记忆：就是 LLM 的消息列表（system/user/assistant/tool 消息）。管理策略：当消息列表超过 Token 预算时，压缩或截断最早的消息。窗口策略（Sliding Window）——只保留最近 N 轮对话，或使用摘要压缩。2）工作记忆：Agent 通过结构化数据（JSON 对象）在工具调用之间传递状态。实现方式：Agent 框架维护一个可读写的工作区（Workspace/Context Store），Agent 可以显式写入和读取关键状态信息。工作记忆存储在 Agent 运行时的内存中，任务完成后可持久化到长期记忆。3）长期记忆：存储在向量数据库中（如 Chroma、Qdrant、PostgreSQL + pgvector）。记忆单元包括——episodic memory（具体事件和事实）、semantic memory（知识和概念）、procedural memory（操作流程和 SOP）。\n\n扩展延伸：记忆的检索和更新——1）检索：RAG 方式（向量相似度搜索），融合 recency（最近访问权重）和 relevance（语义相似度权重）。2）记忆刷新：同一记忆在不同时间被访问，更新其 last_accessed 时间戳，重要记忆附带 access_count 计数。3）记忆压缩（Memory Consolidation）：定期对多条相似记忆做摘要合并，减少存储空间和检索噪声。4）遗忘策略（Forgetting）：长时间未被访问的记忆自动降级或删除（如 30 天未访问的临时记忆自动清除）。5）Memory Reflection（反思记忆）：Agent 定期回顾自己的记忆，发现有价值的模式或因果关系后写入新的 long-term 记忆条目。","hints":["短期记忆由 LLM 窗口承载，工作记忆由框架维护，长期记忆由向量数据库存储","记忆压缩（Consolidation）和遗忘（Forgetting）是记忆系统的关键——不做会无限膨胀"],"tags":["Agent","记忆管理","短期记忆","长期记忆","向量数据库"],"id":149},{"category":"ai_agent","difficulty":"hard","type":"short_answer","title":"Agent 故障恢复策略：降级、重试、补偿与状态重建","content":"请设计 Agent 的故障恢复策略体系，包括降级（Graceful Degradation）、自适应重试（Adaptive Retry）、补偿事务（Compensation）、以及状态重建（State Recovery）在 Agent 工作流中的应用。","answer":"答案：Agent 系统的故障恢复需要分场景处理——1）降级（Graceful Degradation）：当某个工具不可用或 LLM 繁忙时，Agent 自动选择替代方案（如向量搜索不可用时回退到 BM25 全文搜索）。2）自适应重试（Adaptive Retry）：工具调用失败时根据错误类型选择重试策略（网络超时→退避重试、参数错误→不重试直接报错）。3）补偿事务（Compensation）：部分完成的复杂操作需要逆向操作回滚（如通知了 A 但 B 失败，需通知 A 取消）。4）状态重建（State Recovery）：Agent 崩溃后从持久化状态中恢复执行。\n\n解析：降级策略——1）功能降级：核心功能保持运行，非核心功能暂时关闭。如推荐的 RAG 检索不可用时，Agent 仅基于自身知识回答（告知用户信息可能不完整）。2）模型降级：主要 LLM 服务中断时切换到后备模型（如从 GPT-4 降级到 GPT-3.5 或本地模型）。3）超时降级：工具调用超过超时时间时，Agent 判定结果为「未知」继续推进任务，不阻塞整个流程。自适应重试——1）可重试错误：网络超时、速率限制（429）、服务暂时不可用（503）→ 指数退避重试（最多 3 次）。2）不可重试错误：参数校验失败、权限不足、资源不存在 → 立即报错不重试。3）重试抖动（Jitter）：在退避中加入随机抖动，避免惊群效应。\n\n扩展延伸：补偿事务——1）SAGA 模式在 Agent 中的体现：每个 Agent 工具调用都对应一个补偿操作（Compensation Action），如「发邮件给用户」的补偿操作是「发邮件给用户取消」。2）补偿队列：失败的 Agent 任务放入补偿队列，由专门的补偿 Agent 执行逆向操作。状态重建——1）Agent 工作流的 checkpoint 持久化（每完成一个步骤保存一次状态快照到数据库）。2）崩溃恢复：重启时从最新的 checkpoint 加载状态，查询已完成步骤，从失败点继续（而非从头开始）。3）幂等设计：Agent 的所有工具调用必须是幂等的（多次执行相同工具调用产生相同效果），这是状态重建的基础。","hints":["降级的核心是「部分可用比完全不可用好」——Agent 在受限条件下尽量完成任务","状态重建依赖 checkpoint 持久化和工具调用的幂等性"],"tags":["Agent","故障恢复","降级","重试","补偿"],"id":150},{"category":"ai_agent","difficulty":"easy","type":"short_answer","title":"MCP（Model Context Protocol）","content":"什么是 MCP（Model Context Protocol）？它解决了 AI Agent 开发中的什么问题？与 Function Calling 有何区别？","answer":"答案：MCP（Model Context Protocol）是 Anthropic 于 2024 年底提出的开放协议，标准化了 AI 模型与外部工具/数据源的交互方式。它定义了「Host（宿主，如 Claude Desktop）—Client（客户端）—Server（工具提供方）」的三层架构，让模型通过统一协议发现和调用工具。\n\n解析：MCP 要解决的核心痛点是工具集成的碎片化。在 MCP 之前，每个 Agent 框架（LangChain、AutoGPT、Semantic Kernel）都有自己的工具定义和调用方式，工具开发者需要为每个框架写适配器。MCP 统一了工具发现（ListTools）、工具调用（CallTool）、资源访问（ReadResource）的接口协议，就像 USB-C 统一了设备连接标准一样。\n\n扩展延伸：MCP 与 Function Calling 的关系——1）Function Calling 是模型能力（模型输出结构化的函数调用参数），MCP 是协议层（管理工具的发现、认证、调用生命周期）。2）两者互补：MCP 的 Client 端最终调用模型的 Function Calling 能力来触发工具。3）MCP 的价值在于标准化工具生态——任何人只要实现一个 MCP Server，就能被所有支持 MCP 的 Agent 使用。","hints":["从协议分层角度思考 MCP 的价值","MCP vs Function Calling 是不同层次的抽象"],"tags":["MCP","协议","工具集成","标准化"],"id":206},{"category":"ai_agent","difficulty":"medium","type":"short_answer","title":"Multi-Agent 编排模式","content":"Multi-Agent 系统中有哪些常见的编排模式？各模式的适用场景和优缺点是什么？","answer":"答案：常见的 Multi-Agent 编排模式有五种：1）Supervisor 模式——一个主管 Agent 负责任务分配和结果汇总，Worker Agent 执行子任务。适用于任务可清晰拆分的场景（如代码审查：一个主管分配代码给多个 Reviewer）。2）Orchestrator 模式——一个中央调度器定义执行计划，子 Agent 按 DAG 顺序执行。适用于流程固定的场景（如 DevOps 流水线）。3）Swarm 模式——无中心节点，Agent 间直接通信和协商任务分工。适用于动态协作场景（如多个 Research Agent 共同调研一个课题）。4）Debate 模式——多个 Agent 就同一问题独立推理后辩论，最终达成共识。适用于需要多角度分析的场景（如代码审核、决策评估）。5）Pipeline 模式——Agent 按固定顺序串联，上一个的输出是下一个的输入。适用于流程链固定的场景（如数据处理流水线）。\n\n扩展延伸：实际生产系统通常采用混合模式——主流程用 Orchestrator，局部用 Supervisor 动态调配。关键设计考虑——1）通信开销：Agent 间消息传递的延迟和成本（每次通信都是一次 LLM 调用）。2）状态一致性：多个 Agent 如何共享和同步上下文。3）故障隔离：一个 Agent 失败不应拖垮整个系统。","hints":["中心化 vs 去中心化是编排模式的核心维度","生产系统通常混合使用多种模式"],"tags":["Multi-Agent","编排","系统设计","架构模式"],"id":207},{"category":"ai_agent","difficulty":"medium","type":"short_answer","title":"Agent 的上下文窗口管理","content":"长时间运行的 Agent 会面临上下文窗口超限的问题。请介绍常见的上下文管理策略及其优缺点。","answer":"答案：常见的上下文管理策略有五种：1）滑动窗口——只保留最近 N 轮对话历史，丢弃最旧的内容。实现简单，但会丢失长期信息。适用于对话场景。2）摘要压缩——定期将历史对话摘要为简短总结，替换原始内容。能保留核心信息，但有信息损失，且摘要本身消耗 Token。适用于需要长期记忆但不要求精确回忆的场景。3）检索增强——将历史内容分块存入向量数据库，每次查询时检索最相关的历史片段加入上下文。精确保留信息，但增加了延迟和系统复杂度。适用于需要精确回忆特定细节的场景。4）结构化截断——保留 System Prompt 和关键状态，逐步丢弃不重要的中间步骤。需要明确的优先级标记。适用于有固定工作流的场景。5）分层记忆——参考人类记忆的三层模型：工作记忆（完整上下文，当前会话）、短期记忆（摘要，跨会话）、长期记忆（向量化检索）。适用于需要持久化上下文的复杂 Agent。\n\n扩展延伸：实际策略选择取决于 Agent 的任务类型——简单对话用滑动窗口就够了，复杂研究型 Agent 需要用分层记忆。还有一个关键点是 Token 预算的主动监控：在接近上下文窗口限制前就触发压缩或检索策略，而不是等到超限后才处理。这称为「主动上下文管理」。","hints":["Token 预算是 Agent 上下文管理的核心约束","主动管理比被动截断更可靠"],"tags":["上下文管理","Token 优化","记忆系统","性能优化"],"id":208},{"category":"ai_agent","difficulty":"hard","type":"short_answer","title":"Agent 评估体系","content":"如何全面评估一个 Agent 系统的性能？现有的 Agent 基准测试有哪些？评估时需要注意什么？","answer":"答案：Agent 评估分三个维度：1）任务完成度——能否正确完成用户目标（Accuracy、Success Rate、Task Completion Rate）。2）效率——完成任务的成本（Token 消耗、API 调用次数、延迟）。3）稳健性——对异常输入的容忍度（错误恢复率、幻觉率、安全违规次数）。\n\n解析：主流 Agent 基准测试——1）SWE-bench：评估 Agent 解决 GitHub Issue 的能力，包含 2294 个真实 Python 项目 Issue。是软件工程 Agent 的事实标准。2）GAIA：评估通用 AI 助手的多步推理和工具使用能力，包含 466 个需要多步推理的真实世界问题。3）ToolBench：评估工具学习和泛化能力，包含超过 16000 个 API。4）WebArena / VisualWebArena：评估 Agent 在浏览器环境中的网页导航和操作能力。5）AgentBench：多维度评估基准，涵盖操作系统、Web 浏览、购物、数据库等 8 个场景。6）TauBench：评估 Agent 的长期规划和记忆能力，包含需要数千步交互的复杂任务。\n\n扩展延伸：Agent 评估的一个核心挑战是可复现性——LLM 的非确定性输出导致同一任务在不同运行中的结果可能不同。建议——1）每个任务至少运行 3-5 次取统计结果。2）使用 Pass@K 指标（K 次尝试中至少成功一次的比例）。3）区分「确定性失败」和「随机性失败」。4）建立持续评估流水线，每次 Agent 升级后重新跑基准。","hints":["评估需要区分能力维度和效率维度","可复现性是 Agent 评估的核心挑战"],"tags":["评估","基准测试","质量保障","稳健性"],"id":209},{"category":"ai_agent","difficulty":"hard","type":"short_answer","title":"Agent 工具调用的安全防护","content":"Agent 在自主调用工具时面临哪些安全风险？如何设计安全的工具调用防护体系？","answer":"答案：Agent 工具调用的安全风险分多层：1）Prompt Injection——用户输入中嵌入恶意指令操纵 Agent 调用危险工具。2）权限滥用——Agent 在合法上下文中过度使用工具（如读取所有文件而非指定文件）。3）工具滥用——同一工具被高频调用导致资源耗尽（经济风险和 DoS）。4）数据泄露——Agent 将敏感数据通过工具传递给外部服务。5）供应链攻击——恶意 MCP 或工具库窃取数据。\n\n解析：安全防护体系从外到内包含五层：1）输入净化层——在用户输入进入 Agent 前检测和过滤 Prompt Injection 尝试（使用独立的 Guard 模型或模式匹配）。2）权限控制层——每个工具有最小权限原则：定义工具能访问的路径范围、数据范围、调用频率上限。参考 Unix 文件权限模型。3）审批流层——高风险操作（写文件、执行命令、发送网络请求）需要用户显式确认。低风险操作（读取文件、搜索）允许自动执行。4）审计日志层——记录所有工具调用的完整上下文（输入、输出、时间戳、触发链）。用于事后追溯和异常检测。5）沙箱执行层——所有工具调用在隔离环境中执行（容器化或 Serverless 沙箱），限制网络访问和系统调用。\n\n扩展延伸：实际生产中的安全策略——1）分级授权：读操作自动放行，写操作需要确认，高危操作需要二次验证或 MFA。2）速率限制：按用户/按工具设置调用频率上限，防止滥用。3）内容检测：Agent 写出的内容在执行前经过敏感信息检测。4）红队测试：定期模拟攻击测试 Agent 的安全性。","hints":["Prompt Injection 是 Agent 安全最大的挑战","安全是分层设计，没有单点解决方案"],"tags":["安全","工具调用","防护体系","Prompt Injection"],"id":210}];
